// SPDX-License-Identifier: MIT
pragma solidity ^0.8.35;

interface IERC20Minimal {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

contract EasyGameAdvance {
    uint8 public constant LEVEL_COUNT = 17;

    uint256 public constant BPS = 10000;
    uint256 public constant MATRIX_PRIZE_BPS = 7550;
    uint256 public constant DIRECT_REF_BPS = 950;
    uint256 public constant SECOND_REF_BPS = 600;
    uint256 public constant THIRD_REF_BPS = 400;
    uint256 public constant PROJECT_FEE_BPS = 500;

    uint256 public constant WEIGHT_SCALE = 100;
    uint256 public constant BASE_ACTIVATION_WEIGHT = 100;
    uint256 public constant DIRECT_REF_WEIGHT = 100;
    uint256 public constant SECOND_REF_WEIGHT = 50;
    uint256 public constant THIRD_REF_WEIGHT = 25;
    uint256 public constant RECYCLE_MATRIX_WEIGHT = 50;
    uint256 public constant BOX_NFT_WEIGHT = 10;
    uint256 public constant WEEKLY_LOYALTY_WEIGHT = 20;

    uint256 public constant MAX_BASE_WEIGHT_PER_LEVEL = 1000;
    uint256 public constant MAX_REFERRAL_WEIGHT_PER_LEVEL = 2000;
    uint256 public constant MAX_MATRIX_WEIGHT_PER_LEVEL = 2000;
    uint256 public constant MAX_LOYALTY_WEIGHT_PER_LEVEL = 1000;
    uint256 public constant MAX_NFT_WEIGHT_PER_LEVEL = 500;
    uint256 public constant MAX_TOTAL_WEIGHT_PER_LEVEL = 5000;

    uint256 public constant PRIZE_POSITION_BPS = 500;
    uint256 public constant DRAW_REWARD_BPS = 1000;

    address public owner;
    address public projectWallet;
    address public treasuryWallet;
    address public operatorWallet;
    IERC20Minimal public usdcToken;

    mapping(uint8 => uint256) public levelPrices;
    mapping(uint8 => uint256) public levelPricesUsdc;
    mapping(uint8 => bool) public levelAvailable;
    mapping(uint8 => uint256) public levelMatrixSize;

    mapping(address => Player) public players;
    mapping(address => mapping(uint8 => PlayerLevel)) public playerLevels;
    mapping(uint8 => mapping(uint256 => MatrixNode)) public matrixNodes;
    mapping(uint8 => uint256) public nextCellId;
    mapping(uint8 => uint256) public nextOpenParentCellId;
    mapping(uint8 => uint256) public matrixPrizePools;
    mapping(uint8 => uint256) public matrixPrizePoolsUsdc;
    mapping(uint8 => uint256) public totalWeightByLevel;
    mapping(uint8 => uint256) public activeCellsByLevel;
    uint256 public projectFeesAccrued;
    uint256 public projectFeesAccruedUsdc;
    mapping(address => uint256) public claimableReferralBonusUsdc;
    mapping(address => uint256) public claimablePrizeUsdc;
    mapping(address => uint256) public pendingPrizeUsdc;
    mapping(address => mapping(uint8 => uint256)) public claimablePrizeUsdcByLevel;
    mapping(address => mapping(uint8 => uint256)) public pendingPrizeUsdcByLevel;

    mapping(uint8 => address[]) private _levelPlayers;
    mapping(uint8 => mapping(address => bool)) private _levelPlayerSeen;
    mapping(address => mapping(uint8 => WeightBreakdown)) private _levelWeights;

    uint256 private _reentrancyLock = 1;

    struct Player {
        bool exists;
        address wallet;
        address inviter;
        address secondLine;
        address thirdLine;
        uint256 totalTickets;
        uint256 baseWeight;
        uint256 referralWeight;
        uint256 loyaltyWeight;
        uint256 matrixWeight;
        uint256 nftWeight;
        uint256 totalWeight;
        uint256 boxTokens;
        uint256 recycleCount;
        uint256 claimableReferralBonus;
        uint256 claimablePrize;
        uint256 pendingPrize;
        uint256 joinedAt;
        uint256 lastActiveAt;
    }

    struct PlayerLevel {
        bool active;
        bool frozen;
        uint256 tickets;
        uint256 cellId;
        uint256 parentCellId;
        uint256 leftChildCellId;
        uint256 rightChildCellId;
        uint256 cycleCount;
        uint256 levelWeight;
        uint256 claimablePrize;
        uint256 pendingPrize;
    }

    struct MatrixNode {
        uint256 cellId;
        address player;
        uint8 level;
        uint256 parentCellId;
        uint256 leftChildCellId;
        uint256 rightChildCellId;
        bool closed;
        bool prizeCell;
    }

    struct WeightBreakdown {
        uint256 baseWeight;
        uint256 referralWeight;
        uint256 loyaltyWeight;
        uint256 matrixWeight;
        uint256 nftWeight;
    }

    event LevelActivated(
        address indexed player,
        uint8 indexed level,
        uint256 value,
        uint256 cellId
    );
    event PaymentSplit(
        address indexed player,
        uint8 indexed level,
        uint256 matrixPrizeAmount,
        uint256 directReferralAmount,
        uint256 secondLineAmount,
        uint256 thirdLineAmount,
        uint256 projectFeeAmount
    );
    event TokenPaymentSplit(
        address indexed player,
        uint8 indexed level,
        address indexed token,
        uint256 matrixPrizeAmount,
        uint256 directReferralAmount,
        uint256 secondLineAmount,
        uint256 thirdLineAmount,
        uint256 projectFeeAmount
    );
    event ProjectFeeAccrued(
        uint8 indexed level,
        uint256 amount,
        uint256 totalAccrued
    );
    event ProjectFeesWithdrawn(address indexed wallet, uint256 amount);
    event TokenProjectFeeAccrued(
        address indexed token,
        uint8 indexed level,
        uint256 amount,
        uint256 totalAccrued
    );
    event TokenProjectFeesWithdrawn(address indexed token, address indexed wallet, uint256 amount);
    event MatrixPlaced(
        address indexed player,
        uint8 indexed level,
        uint256 indexed cellId,
        uint256 parentCellId
    );
    event ReferralBonusAdded(
        address indexed inviter,
        address indexed invitee,
        uint8 indexed level,
        uint256 bonusAmount,
        uint256 weightAdded
    );
    event SecondLineBonusAdded(
        address indexed inviter,
        address indexed invitee,
        uint8 indexed level,
        uint256 bonusAmount,
        uint256 weightAdded
    );
    event ThirdLineBonusAdded(
        address indexed inviter,
        address indexed invitee,
        uint8 indexed level,
        uint256 bonusAmount,
        uint256 weightAdded
    );
    event WeightUpdated(
        address indexed player,
        uint8 indexed level,
        uint256 totalWeight
    );
    event Recycled(
        address indexed player,
        uint8 indexed level,
        uint256 recycleCount,
        uint256 newCellId
    );
    event BoxTokenGranted(
        address indexed player,
        uint8 indexed level,
        uint256 amount
    );
    event PrizePositionReached(
        address indexed player,
        uint8 indexed level,
        uint256 indexed cellId,
        uint256 amount,
        bool pending
    );
    event TokenPrizePositionReached(
        address indexed player,
        uint8 indexed level,
        address indexed token,
        uint256 cellId,
        uint256 amount,
        bool pending
    );
    event DrawRequested(
        uint8 indexed level,
        uint256 randomSeed,
        uint256 totalWeight
    );
    event DrawWon(
        address indexed winner,
        uint8 indexed level,
        uint256 amount,
        bool pending
    );
    event TokenDrawWon(
        address indexed winner,
        uint8 indexed level,
        address indexed token,
        uint256 amount,
        bool pending
    );
    event ReferralBonusClaimed(address indexed player, uint256 amount);
    event PrizeClaimed(address indexed player, uint8 indexed level, uint256 amount);
    event TokenReferralBonusClaimed(address indexed player, address indexed token, uint256 amount);
    event TokenPrizeClaimed(address indexed player, address indexed token, uint8 indexed level, uint256 amount);
    event LevelFrozen(address indexed player, uint8 indexed level);
    event LevelUnfrozen(address indexed player, uint8 indexed level);
    event LevelPriceChanged(uint8 indexed level, uint256 oldPrice, uint256 newPrice);
    event LevelUsdcPriceChanged(uint8 indexed level, uint256 oldPrice, uint256 newPrice);
    event LevelAvailabilityChanged(uint8 indexed level, bool available);
    event WalletsChanged(address projectWallet, address treasuryWallet, address operatorWallet);
    event UsdcTokenChanged(address indexed oldToken, address indexed newToken);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier nonReentrant() {
        require(_reentrancyLock == 1, "Reentrant call");
        _reentrancyLock = 2;
        _;
        _reentrancyLock = 1;
    }

    constructor(
        address projectWallet_,
        address treasuryWallet_,
        address operatorWallet_,
        address usdcToken_
    ) {
        require(projectWallet_ != address(0), "Project wallet required");
        require(treasuryWallet_ != address(0), "Treasury wallet required");
        require(operatorWallet_ != address(0), "Operator wallet required");
        require(usdcToken_ != address(0), "USDC token required");

        owner = msg.sender;
        projectWallet = projectWallet_;
        treasuryWallet = treasuryWallet_;
        operatorWallet = operatorWallet_;
        usdcToken = IERC20Minimal(usdcToken_);

        levelPrices[1] = 0.05 ether;
        levelPrices[2] = 0.07 ether;
        levelPrices[3] = 0.1 ether;
        levelPrices[4] = 0.14 ether;
        levelPrices[5] = 0.2 ether;
        levelPrices[6] = 0.28 ether;
        levelPrices[7] = 0.4 ether;
        levelPrices[8] = 0.55 ether;
        levelPrices[9] = 0.8 ether;
        levelPrices[10] = 1.1 ether;
        levelPrices[11] = 1.6 ether;
        levelPrices[12] = 2.2 ether;
        levelPrices[13] = 3.2 ether;
        levelPrices[14] = 4.4 ether;
        levelPrices[15] = 6.5 ether;
        levelPrices[16] = 8 ether;
        levelPrices[17] = 12 ether;

        levelPricesUsdc[1] = 50000;
