    function _splitPayment(uint8 level, address playerAddress, uint256 amount) private {
        uint256 matrixPrizeAmount = (amount * MATRIX_PRIZE_BPS) / BPS;
        uint256 directReferralAmount = (amount * DIRECT_REF_BPS) / BPS;
        uint256 secondLineAmount = (amount * SECOND_REF_BPS) / BPS;
        uint256 thirdLineAmount = (amount * THIRD_REF_BPS) / BPS;
        uint256 projectFeeAmount = amount -
            matrixPrizeAmount -
            directReferralAmount -
            secondLineAmount -
            thirdLineAmount;

        Player storage player = players[playerAddress];
        matrixPrizePools[level] += matrixPrizeAmount;

        _creditReferral(
            player.inviter,
            playerAddress,
            level,
            directReferralAmount,
            DIRECT_REF_WEIGHT,
            1
        );
        _creditReferral(
            player.secondLine,
            playerAddress,
            level,
            secondLineAmount,
            SECOND_REF_WEIGHT,
            2
        );
        _creditReferral(
            player.thirdLine,
            playerAddress,
            level,
            thirdLineAmount,
            THIRD_REF_WEIGHT,
            3
        );

        projectFeesAccrued += projectFeeAmount;

        emit PaymentSplit(
            playerAddress,
            level,
            matrixPrizeAmount,
            directReferralAmount,
            secondLineAmount,
            thirdLineAmount,
            projectFeeAmount
        );
        emit ProjectFeeAccrued(level, projectFeeAmount, projectFeesAccrued);
    }

